// Purpose: Validate one-email payload from the Daily Orchestrator.
// V2.6: 'sender' removed from required fields to prevent permanent failure loops on malformed From headers.
const item = $input.first()?.json || {};
const required = ['account','messageId','subject','labelMap','processedLabelId'];
const missing = required.filter(k => item[k] === undefined || item[k] === null || item[k] === '');
if (missing.length) {
  return [{ json: { status: 'failed', messageId: item.messageId || null, category: item.category || null, source: item.source || 'input_validation', reasoning: null, confidence: 0, errorMessage: `Missing required child fields: ${missing.join(', ')}`, ledgerWarning: false } }];
}
return [{ json: { ...item, childStatus: 'started', childExecutionId: String($execution.id) } }];

// Purpose: Use the ledger only as a hint. If lookup fails, keep processing.
const original = $('Validate Input').first()?.json || {};
const row = $input.first()?.json || {};
if (row.error) {
  return [{ json: { ...original, ledgerCheckFailed: true, failureStage: 'ledger_check', errorMessage: row.error?.message || 'Ledger check failed.' } }];
}
const ledgerCompleted = Boolean(row.gmail_message_id && row.status === 'completed');
return [{ json: { ...original, ledgerCompleted, ledgerCategory: row.category || null, ledgerSource: row.source || null, ledgerConfidence: row.confidence ?? null, ledgerReasoning: row.reasoning || null, ledgerProcessedAt: row.processed_at || null } }];

// Purpose: Handle Gemini API response - parse success or fallback on failure.
// V2.6: Sanitized reasoning - fixed safe string, raw error in errorMessage only.
const original = $('Evaluate Ledger Check').first()?.json || {};

// Check if Gemini API call failed (error output from Gemini node)
if ($json.error) {
  const msg = String($json.error?.message || $json.message || 'Gemini API failed.').slice(0, 500);
  return [{ json: { ...original, category: 'please-review', source: 'ai_failed', confidence: 0, reasoning: 'Gemini API failed; safe fallback to please-review.', errorMessage: msg } }];
}

// Parse successful Gemini response
let rawText = '';
let parsed = null;
try {
  rawText = $json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  let cleaned = rawText.replace(/```json\s*/gi, '').replace(/```/g, '').trim();
  const open = cleaned.indexOf('{');
  const close = cleaned.lastIndexOf('}');
  if (open !== -1 && close > open) cleaned = cleaned.substring(open, close + 1);
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { ...original, category: 'please-review', source: 'ai_failed', confidence: 0, reasoning: 'Gemini parse failed; routed to please-review.' } }];
}

const validCategories = ['unimportant','receipts','priority','email-subs','please-review'];
let category = String(parsed.category || '').toLowerCase().trim();
let confidence = Number(parsed.confidence ?? 0);
let reasoning = String(parsed.reasoning || 'No reasoning provided.');

if (String(parsed.messageId) !== String(original.messageId)) {
  category = 'please-review';
  confidence = 0;
  reasoning = 'Gemini messageId mismatch; routed to please-review.';
}
if (!validCategories.includes(category)) {
  category = 'please-review';
  confidence = 0;
  reasoning = 'Invalid Gemini category; routed to please-review.';
}
if (!Number.isFinite(confidence) || confidence < 0.8) {
  category = 'please-review';
  reasoning = `Confidence below threshold: ${confidence}.`;
}

return [{ json: { ...original, category, source: 'ai', confidence, reasoning } }];

// Purpose: Single normalization point for ALL classification paths.
// V2.6: Absorbs ledger reuse, processedLabelId guard with explicit failure shape, labelMap graceful routing.
const j = $json;
const validCategories = ['unimportant','receipts','priority','email-subs','please-review'];

// Ledger reuse path - if ledger already completed, use its classification
let category, source, confidence, reasoning;
if (j.ledgerCompleted && j.ledgerCategory) {
  category = String(j.ledgerCategory).toLowerCase().trim();
  source = j.ledgerSource || 'ledger';
  confidence = j.ledgerConfidence ?? 1;
  reasoning = j.ledgerReasoning || 'Reused ledger classification. Gmail processed label was missing, so labels will be reapplied.';
} else {
  category = String(j.category || 'please-review').toLowerCase().trim();
  source = j.source || 'unknown';
  confidence = j.confidence ?? 0;
  reasoning = j.reasoning || 'No reasoning provided.';
}

// Validate category
if (!validCategories.includes(category)) {
  category = 'please-review';
  reasoning = `${reasoning} Invalid category normalized to please-review.`;
}

// Resolve target label ID
let targetLabelId = j.labelMap?.[category];

// Graceful routing - if target label missing but please-review exists, route there
if (!targetLabelId && j.labelMap?.['please-review']) {
  category = 'please-review';
  targetLabelId = j.labelMap['please-review'];
  reasoning = `${reasoning} Missing target category label; routed to please-review.`;
}

// Guard against empty processedLabelId
if (!j.processedLabelId) {
  return [{
    json: {
      ...j,
      category,
      targetLabelId: null,
      labelReady: false,
      status: 'failed',
      failedAt: 'missing_processed_label_id',
      source,
      confidence,
      reasoning: `${reasoning} processedLabelId is missing; cannot mark as processed.`
    }
  }];
}

return [{
  json: {
    ...j,
    category,
    targetLabelId,
    labelReady: Boolean(targetLabelId),
    source,
    confidence,
    reasoning
  }
}];

// Purpose: Return minimal success result to orchestrator.
// V2.6: Stripped to only the 8 fields the orchestrator needs.
const original = $('Prepare Final Category').first()?.json || {};
const db = $input.first()?.json || {};
const ledgerWarning = Boolean(db.error);
return [{ json: {
  status: 'completed',
  messageId: original.messageId || null,
  category: db.category || original.category || null,
  source: db.source || original.source || null,
  confidence: original.confidence ?? 0,
  reasoning: original.reasoning || null,
  errorMessage: ledgerWarning ? `Gmail processed; ledger update failed: ${db.error?.message || 'unknown ledger error'}` : null,
  ledgerWarning
} }];

// Purpose: Build failure context for emails that could not be fully processed.
// V2.6: Inverted stage detection — checks Apply Processed Label (not Apply Category Label).
function safeNode(name) { try { return $(name).first()?.json || null; } catch (e) { return null; } }
const prepared = safeNode('Prepare Final Category') || safeNode('Evaluate Ledger Check') || safeNode('Validate Input') || $json || {};
const current = $json || {};
const err = current.error?.message || current.message || current.errorMessage || null;
let failureStage = 'processing';
if (prepared.labelReady === false) failureStage = 'missing_label_id';
else if (safeNode('Apply Processed Label')) failureStage = 'apply_processed_label';
else failureStage = 'apply_category_label';
const errorMessage = prepared.labelReady === false ? `Missing Gmail label ID for category: ${prepared.category || 'unknown'}` : (err || `Failed during ${failureStage}.`);
return [{ json: { ...prepared, status: 'failed', failureStage, errorMessage } }];

// Purpose: Return minimal failure result to orchestrator.
// V2.6: Stripped to only the 8 fields the orchestrator needs.
function safeNode(name) { try { return $(name).first()?.json || null; } catch (e) { return null; } }
const failure = safeNode('Build Processing Failure') || $json || {};
return [{ json: {
  status: 'failed',
  messageId: failure.messageId || null,
  category: failure.category || null,
  source: failure.source || 'unknown',
  confidence: failure.confidence ?? 0,
  reasoning: failure.reasoning || null,
  errorMessage: failure.errorMessage || $json.error_message || $json.error?.message || 'Processing failed.',
  ledgerWarning: false
} }];
